const svg = $('#fl-svg'), pick = $('#fl-pick'), Tslider=$('#fl-T'), Tval=$('#fl-Tval'), out=$('#fl-out');
const FIELDS = {
  linear:   { f:(t,[x,y])=>[-x, -0.5*y],                   label:'linear sink', box:10 },
  pendulum: { f:(t,[x,y])=>[y, -Math.sin(x)],              label:'pendulum',   box:7 },
  predator: { f:(t,[x,y])=>[x*(1-y), y*(x-1)],             label:'predator–prey', box:4 }
};
const mk = { linear:[], pendulum:[], predator:[] };
let starts = [[2, 3]]; // default starting points
function render(){
  const key = pick.value; const F = FIELDS[key];
  const box = F.box;
  svg.setAttribute('viewBox', `${-box} ${-box} ${2*box} ${2*box}`);
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  // arrow grid
  const N = 17, step = 2*box/N;
  ensureArrow(svg, 'arr-field', 'var(--mute)');
  for(let i=0;i<N;i++){
    for(let j=0;j<N;j++){
      const x = -box + (i+0.5)*step, y = -box + (j+0.5)*step;
      const [vx,vy] = F.f(0,[x,y]);
      const L = Math.hypot(vx,vy) || 1;
      const s = step*0.35 / L;
      const x2 = x + vx*s, y2 = y + vy*s;
      const line = SVG('line',{x1:x,y1:-y,x2:x2,y2:-y2,stroke:'var(--mute)','stroke-width':0.04,'marker-end':'url(#arr-field)','opacity':0.55});
      svg.appendChild(line);
    }
  }
  // axes
  svg.appendChild(SVG('line',{x1:-box,y1:0,x2:box,y2:0,stroke:'var(--line)','stroke-width':0.03}));
  svg.appendChild(SVG('line',{x1:0,y1:-box,x2:0,y2:box,stroke:'var(--line)','stroke-width':0.03}));
  // orbits
  const T = Number(Tslider.value); const h = 0.01;
  for(const s of starts){
    const pts=[s]; let y=s.slice();
    for(let t=0;t<T;t+=h){
      y = rk4Step(F.f, t, y, h);
      if(Math.abs(y[0])>2*box || Math.abs(y[1])>2*box) break;
      if(pts.length && Math.hypot(y[0]-pts[pts.length-1][0], y[1]-pts[pts.length-1][1])>0.04) pts.push(y.slice());
    }
    const d = pts.map((p,i)=>(i?'L':'M')+p[0]+' '+(-p[1])).join(' ');
    svg.appendChild(SVG('path',{d, fill:'none', stroke:'var(--yellow)', 'stroke-width':0.08}));
    svg.appendChild(SVG('circle',{cx:s[0], cy:-s[1], r:0.14, fill:'var(--yellow)'}));
  }
  out.textContent = `${F.label} · T=${T}\nclick the field to drop an orbit — orbits integrate with RK4.`;
}
function pointerToWorld(e){
  const pt = svg.createSVGPoint(); pt.x = e.clientX; pt.y = e.clientY;
  const m = svg.getScreenCTM(); if(!m) return null;
  const inv = m.inverse(); const w = pt.matrixTransform(inv);
  return [w.x, -w.y];
}
svg.addEventListener('click', e=>{
  const w = pointerToWorld(e); if(!w) return;
  starts.push(w); if(starts.length>6) starts.shift();
  render();
});
pick.addEventListener('change', ()=>{starts = []; render();});
Tslider.addEventListener('input', ()=>{ Tval.textContent = `T=${Tslider.value}`; render(); });
render();

