const svg=$('#li-svg'), out=$('#li-out');
const sa=$('#li-a'), sb=$('#li-b'), sc=$('#li-c'), sd=$('#li-d');
const la=$('#li-aval'), lb=$('#li-bval'), lc=$('#li-cval'), ld=$('#li-dval');
function render(){
  const a=+sa.value, b=+sb.value, c=+sc.value, d=+sd.value;
  la.textContent=`a=${a.toFixed(2)}`; lb.textContent=`b=${b.toFixed(2)}`;
  lc.textContent=`c=${c.toFixed(2)}`; ld.textContent=`d=${d.toFixed(2)}`;
  const tr=a+d, det=a*d-b*c, disc=tr*tr-4*det;
  let type;
  if(Math.abs(det)<1e-9) type='degenerate (zero eigenvalue)';
  else if(det<0) type='saddle';
  else if(Math.abs(tr)<1e-9) type='center (linear) — nonlinear fate needs higher-order';
  else if(disc>=0){
    if(tr<0) type='stable node (real negative eigenvalues)';
    else type='unstable node (real positive eigenvalues)';
  } else {
    if(tr<0) type='stable spiral';
    else type='unstable spiral';
  }
  const f=(t,[x,y])=>[a*x+b*y, c*x+d*y];
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  svg.appendChild(SVG('line',{x1:-5,y1:0,x2:5,y2:0,stroke:'var(--line)','stroke-width':0.02}));
  svg.appendChild(SVG('line',{x1:0,y1:-5,x2:0,y2:5,stroke:'var(--line)','stroke-width':0.02}));
  // tiny orbits from a ring of ICs
  const NIC=12, R=4;
  for(let k=0;k<NIC;k++){
    const ang = 2*Math.PI*k/NIC;
    let y=[R*Math.cos(ang), R*Math.sin(ang)];
    const pts=[y.slice()];
    // integrate forward
    for(let t=0;t<6;t+=0.01){
      y = rk4Step(f,t,y,0.01);
      if(Math.abs(y[0])>8 || Math.abs(y[1])>8) break;
      pts.push(y.slice());
    }
    const d1 = pts.map((p,i)=>(i?'L':'M')+p[0]+' '+(-p[1])).join(' ');
    svg.appendChild(SVG('path',{d:d1, fill:'none', stroke:'var(--cyan)', 'stroke-width':0.04, opacity:0.85}));
  }
  svg.appendChild(SVG('circle',{cx:0,cy:0,r:0.08,fill:'var(--yellow)'}));
  // eigenvalues
  let eig;
  if(disc>=0){
    const s=Math.sqrt(disc);
    eig = [(tr+s)/2, (tr-s)/2].map(v=>v.toFixed(3));
  } else {
    const im = Math.sqrt(-disc)/2;
    eig = [`${(tr/2).toFixed(3)}+${im.toFixed(3)}i`, `${(tr/2).toFixed(3)}-${im.toFixed(3)}i`];
  }
  out.textContent = `A = [[${a.toFixed(2)}, ${b.toFixed(2)}], [${c.toFixed(2)}, ${d.toFixed(2)}]]\n`
    + `tr=${tr.toFixed(3)} · det=${det.toFixed(3)} · disc=${disc.toFixed(3)}\n`
    + `eigenvalues: ${eig.join(', ')}\n`
    + `classification: ${type}`;
}
[sa,sb,sc,sd].forEach(s=>s.addEventListener('input', render));
render();

