const svg=$('#ph-svg'), pick=$('#ph-pick'), mu=$('#ph-mu'), muv=$('#ph-muval'), out=$('#ph-out');
function render(){
  const m = +mu.value; muv.textContent = `μ=${m.toFixed(2)}`;
  let f, box=3, name='';
  switch(pick.value){
    case 'hopf':
      f = (t,[x,y]) => [m*x - y - x*(x*x+y*y), x + m*y - y*(x*x+y*y)];
      name='Hopf normal form'; break;
    case 'saddle':
      f = (t,[x,y]) => [x, -y*(1+m*0.4)]; name='saddle'; break;
    case 'node':
      f = (t,[x,y]) => [-(1+m*0.5)*x, -(2+m*0.3)*y]; name='stable node'; break;
    case 'vanderpol':
      f = (t,[x,y]) => [y, (0.5+m)*(1-x*x)*y - x]; name='Van der Pol'; break;
    case 'predator':
      f = (t,[x,y]) => [x*(1-y), y*(x-1)]; name='Lotka–Volterra (μ ignored)'; box=2.5; break;
  }
  svg.setAttribute('viewBox', `${-box} ${-box} ${2*box} ${2*box}`);
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  // arrow field
  const N=13;
  for(let i=0;i<N;i++) for(let j=0;j<N;j++){
    const x=-box+(i+0.5)*2*box/N, y=-box+(j+0.5)*2*box/N;
    const [u,v]=f(0,[x,y]); const L=Math.hypot(u,v)||1;
    const s=2*box/N*0.3/L;
    svg.appendChild(SVG('line',{x1:x,y1:-y,x2:x+u*s,y2:-(y+v*s),stroke:'var(--mute)','stroke-width':0.015,opacity:0.6}));
  }
  // axes
  svg.appendChild(SVG('line',{x1:-box,y1:0,x2:box,y2:0,stroke:'var(--line)','stroke-width':0.015}));
  svg.appendChild(SVG('line',{x1:0,y1:-box,x2:0,y2:box,stroke:'var(--line)','stroke-width':0.015}));
  // integrate a ring of ICs
  const NIC=10, R=box*0.7, T=15, h=0.01;
  for(let k=0;k<NIC;k++){
    const a=2*Math.PI*k/NIC;
    let y=[R*Math.cos(a), R*Math.sin(a)];
    const pts=[y.slice()];
    for(let t=0;t<T;t+=h){
      y=rk4Step(f,t,y,h);
      if(Math.abs(y[0])>2*box||Math.abs(y[1])>2*box) break;
      pts.push(y.slice());
    }
    const d=pts.map((p,i)=>(i?'L':'M')+p[0]+' '+(-p[1])).join(' ');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--yellow)','stroke-width':0.02,opacity:0.9}));
  }
  // another ring closer to origin
  for(let k=0;k<NIC;k++){
    const a=2*Math.PI*k/NIC + Math.PI/NIC;
    let y=[R*0.3*Math.cos(a), R*0.3*Math.sin(a)];
    const pts=[y.slice()];
    for(let t=0;t<T;t+=h){
      y=rk4Step(f,t,y,h);
      if(Math.abs(y[0])>2*box||Math.abs(y[1])>2*box) break;
      pts.push(y.slice());
    }
    const d=pts.map((p,i)=>(i?'L':'M')+p[0]+' '+(-p[1])).join(' ');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--cyan)','stroke-width':0.02,opacity:0.85}));
  }
  // origin as fixed point (most presets)
  svg.appendChild(SVG('circle',{cx:0,cy:0,r:0.08,fill:'var(--pink)'}));
  out.textContent = `${name} · μ=${m.toFixed(2)}\nyellow = orbits from outer ring · cyan = orbits from inner ring.`;
}
pick.addEventListener('change',render); mu.addEventListener('input',render); render();

