pick.addEventListener('change',render); mu.addEventListener('input',render); render();

const svg=$('#vd-svg'), mu=$('#vd-mu'), muv=$('#vd-muval'), out=$('#vd-out');
function render(){
  const m=+mu.value; muv.textContent=`μ=${m.toFixed(2)}`;
  const f=(t,[x,y])=>[y, m*(1-x*x)*y - x];
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  svg.appendChild(SVG('line',{x1:-4,y1:0,x2:4,y2:0,stroke:'var(--line)','stroke-width':0.015}));
  svg.appendChild(SVG('line',{x1:0,y1:-4,x2:0,y2:4,stroke:'var(--line)','stroke-width':0.015}));
  // arrow field
  const N=14;
  for(let i=0;i<N;i++) for(let j=0;j<N;j++){
    const x=-4+(i+0.5)*8/N, y=-4+(j+0.5)*8/N;
    const [u,v]=f(0,[x,y]); const L=Math.hypot(u,v)||1;
    const s=8/N*0.3/L;
    svg.appendChild(SVG('line',{x1:x,y1:-y,x2:x+u*s,y2:-(y+v*s),stroke:'var(--mute)','stroke-width':0.02,opacity:0.5}));
  }
  // multiple orbits
  const starts = [[0.3,0.3],[3.5,0],[0,3.5],[-3.5,0],[0,-3.5]];
  const colors = ['var(--yellow)','var(--cyan)','var(--cyan)','var(--cyan)','var(--cyan)'];
  for(let k=0;k<starts.length;k++){
    let y=starts[k].slice(); const pts=[y.slice()];
    const T=30, h=0.005;
    for(let t=0;t<T;t+=h){
      y=rk4Step(f,t,y,h);
      if(Math.abs(y[0])>6||Math.abs(y[1])>10) break;
      pts.push(y.slice());
    }
    const d=pts.map((p,i)=>(i?'L':'M')+p[0]+' '+(-p[1])).join(' ');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:colors[k],'stroke-width':0.025,opacity:0.9}));
  }
  // origin
  svg.appendChild(SVG('circle',{cx:0,cy:0,r:0.08,fill:'var(--pink)'}));
