const svg=$('#co-svg'), pick=$('#co-pick'), rs=$('#co-r'), xs=$('#co-x0');
const rv=$('#co-rval'), xv=$('#co-x0val'), out=$('#co-out');
function render(){
  const r=+rs.value, x0=+xs.value;
  rv.textContent=`r=${r.toFixed(3)}`; xv.textContent=`x₀=${x0.toFixed(2)}`;
  let f; const p = pick.value;
  switch(p){
    case 'logistic': f = x=>r*x*(1-x); break;
    case 'tent':     f = x=>(x<0.5 ? 2*x : 2*(1-x)); break;
    case 'doubling': f = x=>(2*x)%1; break;
    case 'sine':     f = x=>r/4*Math.sin(Math.PI*x); break;  // scale so max ≈ r/4
  }
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  // frame
  svg.appendChild(SVG('rect',{x:0,y:-1,width:1,height:1,fill:'none',stroke:'var(--line)','stroke-width':0.003}));
  // diagonal
  svg.appendChild(SVG('line',{x1:0,y1:0,x2:1,y2:-1,stroke:'var(--mute)','stroke-width':0.004}));
  // curve
  const M=300;
  let d='';
  for(let i=0;i<=M;i++){ const x=i/M, y=f(x); d += (i?'L':'M')+x+' '+(-y); }
  svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--cyan)','stroke-width':0.006}));
  // cobweb
  let x=x0; let d2=`M${x} 0`;
  for(let i=0;i<80;i++){
    const y=f(x);
    d2 += ` L${x} ${-y}`;
    d2 += ` L${y} ${-y}`;
    x = y;
    if(!isFinite(x)) break;
  }
  svg.appendChild(SVG('path',{d:d2,fill:'none',stroke:'var(--yellow)','stroke-width':0.004,opacity:0.95}));
  svg.appendChild(SVG('circle',{cx:x0,cy:0,r:0.012,fill:'var(--yellow)'}));
  const xlast = x;
  out.textContent = `${p} · r=${r.toFixed(3)} · x₀=${x0.toFixed(2)}\nafter 80 iterates, x ≈ ${xlast.toFixed(5)}`;
}
