const svg=$('#ly-svg'), rs=$('#ly-r'), rv=$('#ly-rval'), out=$('#ly-out');
const R0=2.8, R1=4.0;
// precompute lambda(r)
const data = [];
const NR=600, BURN=400, N=1000;
for(let k=0;k<NR;k++){
  const r = R0 + (R1-R0)*k/(NR-1);
  let x=0.4;
  for(let i=0;i<BURN;i++) x = r*x*(1-x);
  let s=0, m=0;
  for(let i=0;i<N;i++){
    x = r*x*(1-x);
    const d = Math.abs(r - 2*r*x);
    if(d>0){ s += Math.log(d); m++; }
  }
  data.push([r, s/m]);
}
function render(){
  const r = +rs.value; rv.textContent = `r=${r.toFixed(3)}`;
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  // frame
  svg.appendChild(SVG('rect',{x:R0,y:-1.2,width:R1-R0,height:2,fill:'var(--panel2)',opacity:0.4}));
  // zero line
  svg.appendChild(SVG('line',{x1:R0,y1:0,x2:R1,y2:0,stroke:'var(--mute)','stroke-width':0.005}));
  // lambda curve  (note: svg y-axis flipped; lambda>0 is up, so y=-lambda)
  let d = '';
  for(let i=0;i<data.length;i++){
    const [rr,ll] = data[i];
    const y = -Math.max(-1.2, Math.min(0.8, ll));
    d += (i?'L':'M')+rr+' '+y;
  }
  svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--yellow)','stroke-width':0.006}));
  // vertical line at r
  svg.appendChild(SVG('line',{x1:r,y1:-1.2,x2:r,y2:0.8,stroke:'var(--pink)','stroke-width':0.006,opacity:0.9}));
  // lookup value
  const idx = Math.min(data.length-1, Math.max(0, Math.round((r-R0)/(R1-R0)*(data.length-1))));
  const lamHere = data[idx][1];
  out.textContent = `λ(${r.toFixed(3)}) ≈ ${lamHere.toFixed(3)}\n`
    + `λ>0: chaotic (positive Lyapunov exponent) · λ<0: periodic attractor · windows of λ<0 inside chaos are periodic islands.`;
}
