const svg=$('#dv-svg'), pick=$('#dv-pick'), Ts=$('#dv-T'), Tv=$('#dv-Tval'), out=$('#dv-out');
const FIELDS = {
  hamil:  { f:(t,[x,y])=>[y, -x],        div:'0 (conservative)' },
  damped: { f:(t,[x,y])=>[y, -x - 0.3*y], div:'-0.3 (dissipative)' },
  expand: { f:(t,[x,y])=>[x, y],          div:'+2 (expanding)' }
};
function render(){
  const T=+Ts.value; Tv.textContent=`T=${T.toFixed(2)}`;
  const F = FIELDS[pick.value];
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  svg.appendChild(SVG('line',{x1:-4,y1:0,x2:4,y2:0,stroke:'var(--line)','stroke-width':0.015}));
  svg.appendChild(SVG('line',{x1:0,y1:-4,x2:0,y2:4,stroke:'var(--line)','stroke-width':0.015}));
  // initial blob: ring of points in a disc at (2, 0) radius 0.6
  const NB = 80;
  const pts0 = [];
  for(let k=0;k<NB;k++){
    const a = 2*Math.PI*k/NB;
    pts0.push([2 + 0.6*Math.cos(a), 0.6*Math.sin(a)]);
  }
  // initial outline
  const d0 = pts0.map((p,i)=>(i?'L':'M')+p[0]+' '+(-p[1])).join(' ')+' Z';
  svg.appendChild(SVG('path',{d:d0,fill:'none',stroke:'var(--mute)','stroke-width':0.03,'stroke-dasharray':'0.08 0.08'}));
  // forward image
  const h=0.01;
  const pts = pts0.map(p=>{ let y=p.slice(); for(let t=0;t<T;t+=h) y=rk4Step(F.f,t,y,h); return y; });
  const d1 = pts.map((p,i)=>(i?'L':'M')+p[0]+' '+(-p[1])).join(' ')+' Z';
  svg.appendChild(SVG('path',{d:d1,fill:'var(--yellow)',fillOpacity:0.25,stroke:'var(--yellow)','stroke-width':0.03}));
  // quick numerical volume (via shoelace)
  function area(P){ let s=0; for(let i=0;i<P.length;i++){ const [x1,y1]=P[i], [x2,y2]=P[(i+1)%P.length]; s += x1*y2-x2*y1; } return Math.abs(s)/2; }
  const A0 = area(pts0), A1 = area(pts);
  out.textContent = `${pick.options[pick.selectedIndex].textContent} · div X = ${F.div}\n`
    + `vol(U) = ${A0.toFixed(3)} · vol(Φ_T(U)) = ${A1.toFixed(3)} · ratio = ${(A1/A0).toFixed(3)}`;
}
