const svg=$('#po-svg'), cs=$('#po-c'), cv=$('#po-cval'), out=$('#po-out');
function render(){
  const c=+cs.value; cv.textContent=`c=${c.toFixed(2)}`;
  const a=0.2, b=0.2;
  const f=(t,[x,y,z])=>[-y-z, x+a*y, b+z*(x-c)];
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  svg.appendChild(SVG('line',{x1:-10,y1:0,x2:10,y2:0,stroke:'var(--line)','stroke-width':0.02}));
  svg.appendChild(SVG('line',{x1:0,y1:-10,x2:0,y2:10,stroke:'var(--line)','stroke-width':0.02}));
  // integrate, collect crossings of z=0 with zdot>0
  let y=[0.1, 0.0, 0.0];
  const h=0.01;
  // skip transient
  for(let i=0;i<20000;i++) y = rk4Step(f,0,y,h);
  const pts=[];
  let prevZ = y[2];
  for(let i=0;i<200000 && pts.length<500;i++){
    const yprev = y.slice();
    y = rk4Step(f,0,y,h);
    if(prevZ<0 && y[2]>=0){
      // linear interp
      const r = -prevZ/(y[2]-prevZ);
      const xi = yprev[0] + r*(y[0]-yprev[0]);
      const yi = yprev[1] + r*(y[1]-yprev[1]);
      pts.push([xi,yi]);
    }
    prevZ = y[2];
  }
  for(const [x,y2] of pts){
    svg.appendChild(SVG('circle',{cx:x, cy:-y2, r:0.05, fill:'var(--yellow)', opacity:0.85}));
  }
  out.textContent = `Rössler (a=0.2, b=0.2, c=${c.toFixed(2)}) · ${pts.length} crossings of z=0, ż>0\nthin curve at small c (periodic) · fattens into a fractal as c grows (chaos).`;
}
