  svg.appendChild(SVG('line',{x1:0,y1:-10,x2:0,y2:10,stroke:'var(--line)','stroke-width':0.02}));
  // integrate, collect crossings of z=0 with zdot>0
  let y=[0.1, 0.0, 0.0];
  const h=0.01;
  // skip transient
  for(let i=0;i<20000;i++) y = rk4Step(f,0,y,h);
  const pts=[];
  let prevZ = y[2];
  for(let i=0;i<200000 && pts.length<500;i++){
    const yprev = y.slice();
    y = rk4Step(f,0,y,h);
    if(prevZ<0 && y[2]>=0){
      // linear interp
      const r = -prevZ/(y[2]-prevZ);
      const xi = yprev[0] + r*(y[0]-yprev[0]);
      const yi = yprev[1] + r*(y[1]-yprev[1]);
      pts.push([xi,yi]);
    }
    prevZ = y[2];
  }
  for(const [x,y2] of pts){
    svg.appendChild(SVG('circle',{cx:x, cy:-y2, r:0.05, fill:'var(--yellow)', opacity:0.85}));
  }
  out.textContent = `Rössler (a=0.2, b=0.2, c=${c.toFixed(2)}) · ${pts.length} crossings of z=0, ż>0\nthin curve at small c (periodic) · fattens into a fractal as c grows (chaos).`;
}
cs.addEventListener('input', render); render();

const svg=$('#sy-svg'), xs=$('#sy-x'), xv=$('#sy-xval'), out=$('#sy-out');
function render(){
  const x0=+xs.value; xv.textContent=`x₀=${x0.toFixed(3)}`;
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  // grid of digits: ROWS iterates, COLS=16 bits shown per iterate
  const ROWS=10, COLS=16;
  const cellW=30, cellH=16;
  let x=x0;
  for(let r=0;r<ROWS;r++){
    // compute first COLS binary digits of x
    let t=x;
    for(let c=0;c<COLS;c++){
      t = t*2;
      const b = t>=1 ? 1 : 0;
      if(b) t -= 1;
      // cell
      const cx = 10 + c*cellW, cy = 5 + r*cellH;
      svg.appendChild(SVG('rect',{x:cx, y:cy, width:cellW-2, height:cellH-2,
        fill: b ? 'var(--yellow)' : 'var(--panel2)',
        stroke:'var(--line)','stroke-width':0.5}));
      const tx = SVG('text',{x:cx+(cellW-2)/2, y:cy+cellH-5, 'text-anchor':'middle','font-size':11,
        fill: b ? '#111' : 'var(--mute)'});
      tx.textContent = b ? '1' : '0';
      svg.appendChild(tx);
    }
    // label row
    const lbl = SVG('text',{x:502, y:5+r*cellH+12, 'font-size':11, fill:'var(--mute)'});
    lbl.textContent = `x_${r}≈${x.toFixed(4)}`;
    svg.appendChild(lbl);
    x = (2*x) % 1;
  }
  out.textContent = `iterate binary digits of $x$ under $f(x)=2x\\bmod 1$; each row is the shift of the row above it.\nitinerary = sequence of leading bits (read down the left column): gives $\\sigma(x)\\in\\{0,1\\}^{\\mathbb{N}}$.`;
}
xs.addEventListener('input', render); render();

