const svg=$('#er-svg'), xs=$('#er-x'), xv=$('#er-xval'), out=$('#er-out');
function render(){
  const x0=+xs.value; xv.textContent=`x₀=${x0.toFixed(3)}`;
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  // frame: x-axis (N, plotted as fraction), y-axis 0..1
  svg.appendChild(SVG('rect',{x:0,y:-1,width:1,height:1,fill:'var(--panel2)',opacity:0.3}));
  // horizontal line at 1/2
  svg.appendChild(SVG('line',{x1:0,y1:-0.5,x2:1,y2:-0.5,stroke:'var(--green)','stroke-width':0.003,opacity:0.7}));
  // label
  const lbl = SVG('text',{x:0.01, y:-0.52, 'font-size':0.03, fill:'var(--green)'}); lbl.textContent='1/2';
  svg.appendChild(lbl);
  // compute running average
  let x=x0, sum=0;
  const N=2000;
  let d='';
  for(let k=1;k<=N;k++){
    x = (2*x) % 1;
    sum += x;
    const avg = sum/k;
    const X = k/N, Y = -avg;
    d += (k===1?'M':'L')+X+' '+Y;
  }
  svg.appendChild(SVG('path',{d, fill:'none', stroke:'var(--yellow)', 'stroke-width':0.005}));
  // last value
  const xEnd = (function(){ let xx=x0, s=0; for(let i=0;i<N;i++){ xx=(2*xx)%1; s+=xx; } return s/N; })();
  out.textContent = `x₀=${x0.toFixed(3)} · N=${N} · running mean ≈ ${xEnd.toFixed(4)} (space average = 0.5 by Birkhoff).`;
}
xs.addEventListener('input', render); render();

