const svg=$('#lo-svg');
const ss=$('#lo-s'), bs=$('#lo-b'), rs=$('#lo-r');
const sv=$('#lo-sval'), bv=$('#lo-bval'), rv=$('#lo-rval');
const out = svg.parentElement.querySelector('.readout');
// precomputed trajectory, recomputed when parameters change
let traj = [];
function integrate(sigma, beta, rho, N, h){
  let y=[0.5, 0.5, 0.5]; const f=(t,[x,y2,z])=>[sigma*(y2-x), rho*x-y2-x*z, x*y2-beta*z];
  // transient
  for(let i=0;i<2000;i++) y = rk4Step(f,0,y,h);
  const out=[];
  for(let i=0;i<N;i++){ y = rk4Step(f,0,y,h); out.push(y.slice()); }
  return out;
}
function recompute(){
  const sigma=+ss.value, beta=+bs.value, rho=+rs.value;
  sv.textContent=`σ=${sigma.toFixed(1)}`; bv.textContent=`β=${beta.toFixed(2)}`; rv.textContent=`ρ=${rho.toFixed(1)}`;
  traj = integrate(sigma, beta, rho, 10000, 0.005);
  draw();
}
function draw(){
  const yaw = view.yaw, pitch = view.pitch;
  const step = view.dragging ? 5 : 1; // decimate on drag
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  // bounds: fixed viewBox, scale world coords
  const scale = 6;
  const cx = 0, cy = -50; // offset so the attractor sits near center
  // project & build path
  const pts = [];
  for(let i=0;i<traj.length;i+=step){
    const [x,y,z] = traj[i];
    // center around (0,0,27)
    const [X,Y,Z] = proj3([x*scale, y*scale, (z-27)*scale], yaw, pitch);
    pts.push([X + cx, -Y + cy, Z]);  // SVG y flipped
  }
  // draw in segments colored by depth Z (front = brighter)
  // simple single path for speed
  let d = '';
  for(let i=0;i<pts.length;i++){ d += (i?'L':'M')+pts[i][0]+' '+pts[i][1]; }
  svg.appendChild(SVG('path',{d, fill:'none', stroke:'var(--cyan)', 'stroke-width':0.7, opacity:0.9}));
  // axes at origin (projected)
  const O = proj3([0,0,-27*scale], yaw, pitch);
  const Xax = proj3([5*scale,0,-27*scale], yaw, pitch);
  const Yax = proj3([0,5*scale,-27*scale], yaw, pitch);
  const Zax = proj3([0,0,-22*scale], yaw, pitch);
  function vp(P){ return [P[0]+cx, -P[1]+cy]; }
  svg.appendChild(SVG('line',{x1:vp(O)[0],y1:vp(O)[1],x2:vp(Xax)[0],y2:vp(Xax)[1],stroke:'var(--pink)','stroke-width':1,opacity:0.6}));
  svg.appendChild(SVG('line',{x1:vp(O)[0],y1:vp(O)[1],x2:vp(Yax)[0],y2:vp(Yax)[1],stroke:'var(--green)','stroke-width':1,opacity:0.6}));
  svg.appendChild(SVG('line',{x1:vp(O)[0],y1:vp(O)[1],x2:vp(Zax)[0],y2:vp(Zax)[1],stroke:'var(--violet)','stroke-width':1,opacity:0.6}));
  // legend in viewport coords
  const legend = SVG('g',{transform:'translate(-230, 170)'});
  const lbl1 = SVG('text',{x:0,y:0,'font-size':11,fill:'var(--mute)'});
  lbl1.textContent = `σ=${(+ss.value).toFixed(1)} · β=${(+bs.value).toFixed(2)} · ρ=${(+rs.value).toFixed(1)}`;
  legend.appendChild(lbl1);
  const lbl2 = SVG('text',{x:0,y:14,'font-size':11,fill:'var(--mute)'});
  lbl2.textContent = `yaw=${yaw.toFixed(2)} · pitch=${pitch.toFixed(2)} — drag to rotate`;
  legend.appendChild(lbl2);
  svg.appendChild(legend);
}
const view = make3DDraggable(svg, draw, { yaw: 0.6, pitch: 0.4 });
[ss, bs, rs].forEach(s=>s.addEventListener('input', recompute));
recompute();

